"""
AI Detection Test Dataset - 100-PR Accuracy Validation

SDLC Stage: 04 - BUILD
Sprint: 42 - AI Detection & Validation Pipeline
Framework: SDLC 5.1.1
Day: 5 - Test Dataset Validation

Purpose:
Provide a comprehensive test dataset of 100 PRs for validating
AI detection accuracy. Target: ≥85% accuracy.

Dataset Composition:
- 25 Cursor PRs
- 25 GitHub Copilot PRs
- 15 Claude Code PRs
- 10 ChatGPT PRs
- 5 Windsurf PRs
- 5 Other AI tools (Cody, Tabnine)
- 15 Human-written PRs (control group)
"""

from dataclasses import dataclass
from typing import List, Optional

from app.services.ai_detection import AIToolType


@dataclass
class TestPR:
    """Test PR data for accuracy validation."""

    id: str
    title: str
    body: str
    commits: List[dict]
    diff: str
    expected_tool: Optional[AIToolType]
    expected_detected: bool
    category: str  # "cursor", "copilot", "claude", "chatgpt", "windsurf", "other", "human"


